import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { fetchProducts } from "../services/api";

import logo from "../assets/logo.png";

const CATEGORIES = [
  "Todas",
  "Cepillos",
  "Pastas dentales",
  "Hilo dental",
  "Blanqueadores",
  "Enjuague bucal",
  "Otros",
];

const categoryColors = {
  Cepillos: "#dbeafe",
  "Pastas dentales": "#dcfce7",
  "Hilo dental": "#fef9c3",
  Blanqueadores: "#ede9fe",
  "Enjuague bucal": "#ffedd5",
  Otros: "#f1f5f9",
};

const styles = {
  page: {
    minHeight: "100vh",
    backgroundColor: "#f0f9ff",
  },

  carousel: {
    width: "100%",
    height: "500px",
    overflow: "hidden",
    backgroundColor: "#fff",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
  },

  carouselOverlay: {
    width: "100%",
    height: "100%",
    backgroundColor: "rgba(0,0,0,.35)",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    justifyContent: "center",
    color: "white",
    textAlign: "center",
    padding: "1.5rem",
  },

  carouselTitle: {
    fontSize: "2.2rem",
    fontWeight: "600",
    marginBottom: "0.3rem",
  },

  carouselSubtitle: {
    fontSize: "1.5rem",
    maxWidth: "650px",
    opacity: 0.95,
  },

  container: {
    maxWidth: "1100px",
    margin: "0 auto",
    padding: "2rem",
  },

  filterRow: {
    display: "flex",
    gap: "0.6rem",
    flexWrap: "wrap",
    marginBottom: "2rem",
  },

  filterBtn: (active) => ({
    padding: "0.45rem 1.1rem",
    borderRadius: "20px",
    border: "1px solid #e2e8f0",
    backgroundColor: active ? "#32d5d5" : "white",
    color: active ? "white" : "#475569",
    fontWeight: "600",
    fontSize: "0.85rem",
    cursor: "pointer",
  }),

  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fill, minmax(260px, 1fr))",
    gap: "1.5rem",
  },

  card: {
    backgroundColor: "white",
    borderRadius: "14px",
    boxShadow: "0 2px 12px rgba(0,0,0,0.08)",
    overflow: "hidden",
    display: "flex",
    flexDirection: "column",
  },

  cardImg: {
    width: "100%",
    height: "180px",
    objectFit: "cover",
  },

  cardBody: {
    padding: "1.2rem",
    display: "flex",
    flexDirection: "column",
    gap: "0.5rem",
  },

  categoryBadge: (cat) => ({
    display: "inline-block",
    padding: "0.2rem 0.7rem",
    borderRadius: "20px",
    fontSize: "0.75rem",
    fontWeight: "600",
    backgroundColor: categoryColors[cat] || "#f1f5f9",
    alignSelf: "flex-start",
  }),

  productName: {
    fontSize: "1rem",
    fontWeight: "700",
  },

  productDesc: {
    fontSize: "0.85rem",
    color: "#64748b",
  },

  priceRow: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
  },

  price: {
    fontSize: "1.2rem",
    fontWeight: "700",
    color: "#32d5d5",
  },

  stock: (n) => ({
    fontSize: "0.78rem",
    color: n === 0 ? "#ef4444" : "#16a34a",
    fontWeight: "600",
  }),

  addBtn: (inCart, outOfStock) => ({
    width: "100%",
    padding: "0.75rem",
    borderRadius: "8px",
    border: "none",
    fontWeight: "600",
    cursor: outOfStock ? "not-allowed" : "pointer",
    backgroundColor: outOfStock ? "#e2e8f0" : inCart ? "#dcfce7" : "#32d5d5",
    color: outOfStock ? "#94a3b8" : inCart ? "#16a34a" : "white",
  }),

  cartBar: {
    position: "fixed",
    bottom: 0,
    left: 0,
    right: 0,
    backgroundColor: "#32d5d5",
    color: "white",
    padding: "1rem 2rem",
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    zIndex: 100,
  },

  cartBtn: {
    backgroundColor: "white",
    color: "#32d5d5",
    border: "none",
    borderRadius: "8px",
    padding: "0.6rem 1.2rem",
    fontWeight: "700",
    cursor: "pointer",
  },

  modalOverlay: {
    position: "fixed",
    inset: 0,
    backgroundColor: "rgba(0,0,0,0.4)",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    zIndex: 200,
  },

  modal: {
    backgroundColor: "white",
    borderRadius: "16px",
    padding: "2rem",
    width: "100%",
    maxWidth: "480px",
  },
};

export default function Store() {
  const [products, setProducts] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [activeCategory, setActiveCategory] = useState("Todas");
  const [cart, setCart] = useState([]);
  const [showCart, setShowCart] = useState(false);
  const [loading, setLoading] = useState(true);

  const navigate = useNavigate();
  const [currentImage, setCurrentImage] = useState(0);

  const slides = [
    {
      image:
        "https://gacetamedica.com/wp-content/uploads/2023/06/GettyImages-1409041204.jpg",
      title: "Tu salud importa",
      subtitle: "Jornadas de atención gratuita",
    },
    {
      image:
        "https://cdn.firespring.com/images/80f7ee1f-f74d-4840-ad81-4eb596834a04.jpg",
      title: "Tu sonrisa es digna",
      subtitle: "Atención personalizada",
    },
  ];

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentImage((p) => (p + 1) % slides.length);
    }, 3000);

    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    fetchProducts().then((res) => {
      setProducts(res.data || []);
      setFiltered(res.data || []);
      setLoading(false);
    });
  }, []);

  const handleFilter = (cat) => {
    setActiveCategory(cat);
    setFiltered(
      cat === "Todas" ? products : products.filter((p) => p.category === cat),
    );
  };

  const handleAddToCart = (product) => {
    setCart((prev) => {
      const exists = prev.find((i) => i.id === product.id);

      if (exists) {
        return prev.map((i) =>
          i.id === product.id ? { ...i, qty: i.qty + 1 } : i,
        );
      }

      return [...prev, { ...product, qty: 1 }];
    });
  };

  const cartCount = cart.reduce((a, b) => a + b.qty, 0);
  const cartTotal = cart.reduce((a, b) => a + b.price * b.qty, 0);

  return (
    <div style={styles.page}>
      <div style={styles.carousel}>
        <div
          style={{
            width: "100%",
            height: "100%",
            backgroundImage: `url(${slides[currentImage].image})`,
            backgroundSize: "cover",
            backgroundPosition: "center",
          }}
        >
          <div style={styles.carouselOverlay}>
            <h1 style={styles.carouselTitle}>{slides[currentImage].title}</h1>
            <p style={styles.carouselSubtitle}>
              {slides[currentImage].subtitle}
            </p>
          </div>
        </div>
      </div>

      <div style={styles.container}>
        <div style={styles.filterRow}>
          {CATEGORIES.map((c) => (
            <button
              key={c}
              style={styles.filterBtn(activeCategory === c)}
              onClick={() => handleFilter(c)}
            >
              {c}
            </button>
          ))}
        </div>

        {loading ? (
          <p>Cargando...</p>
        ) : (
          <div style={styles.grid}>
            {filtered.map((p) => {
              const outOfStock = p.stock === 0;
              const inCart = cart.some((i) => i.id === p.id);

              return (
                <div key={p.id} style={styles.card}>
                  <img src={p.imageUrl} style={styles.cardImg} />

                  <div style={styles.cardBody}>
                    <span style={styles.categoryBadge(p.category)}>
                      {p.category}
                    </span>

                    <div style={styles.productName}>{p.name}</div>

                    <div style={styles.productDesc}>{p.description || "—"}</div>

                    <div style={styles.priceRow}>
                      <div style={styles.price}>${p.price}</div>
                      <div style={styles.stock(p.stock)}>
                        {p.stock} disponibles
                      </div>
                    </div>

                    <button
                      style={styles.addBtn(inCart, outOfStock)}
                      onClick={() => handleAddToCart(p)}
                      disabled={outOfStock}
                    >
                      {outOfStock
                        ? "No disponible"
                        : inCart
                          ? "En el carrito"
                          : "Agregar al carrito"}
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {cartCount > 0 && (
        <div style={styles.cartBar}>
          <div>
            🛒 {cartCount} productos • ${cartTotal.toFixed(2)}
          </div>

          <button style={styles.cartBtn} onClick={() => setShowCart(true)}>
            Ver carrito
          </button>
        </div>
      )}

      {showCart && (
        <div style={styles.modalOverlay} onClick={() => setShowCart(false)}>
          <div style={styles.modal} onClick={(e) => e.stopPropagation()}>
            <h2>Carrito</h2>

            {cart.map((item) => (
              <div key={item.id}>
                {item.name} x{item.qty}
              </div>
            ))}

            <p>Total: ${cartTotal.toFixed(2)}</p>

            <button onClick={() => navigate("/checkout", { state: { cart } })}>
              Ir al checkout
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
